<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>Random Joke Generator</title>
    <style>
        body {
            font-family: Arial, Helvetica, sans-serif;
            text-align: center;
            margin-top: 5rem;
        }
        #jokeBox {
            margin-top: 2rem;
            padding: 1rem;
            border: 2px solid #333;
            max-width: 600px;
            margin-left: auto;
            margin-right: auto;
            font-size: 1.2rem;
        }
        button {
            padding: .8rem 1.5rem;
            font-size: 1rem;
            cursor: pointer;
        }
    </style>
</head>
<body>

    <h1>🃏 Random Joke Generator 🃏</h1>

    <!-- The joke will be displayed here -->
    <div id="jokeBox">Click the button to see a joke!</div>

    <button id="tellJokeBtn">Tell me a joke</button>

    <script>
        // 4 jokes – feel free to replace them with any jokes you like
        const jokes = [
            "Why don’t scientists trust atoms? Because they make up everyth[7D[K
everything!",
            "I told my wife she was drawing her eyebrows too high. She look[4D[K
looked surprised.",
            "What do you call a fake noodle? An impasta.",
            "Why did the scarecrow win an award? He was outstanding in his [K
field."
        ];

        // Grab references to DOM elements
        const jokeBox = document.getElementById('jokeBox');
        const btn       = document.getElementById('tellJokeBtn');

        // Function that picks a random joke and shows it
        function showRandomJoke() {
            const randomIndex = Math.floor(Math.random() * jokes.length);
            const randomJoke  = jokes[randomIndex];
            jokeBox.textContent = randomJoke;
        }

        // Attach click handler
        btn.addEventListener('click', showRandomJoke);
    </script>

</body>
</html>
```

